      <svg
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          pointerEvents: 'none',
          zIndex: 0,
        }}
      >
        {state.connections.map(conn => (
          <ConnectionWire
            key={conn.id}
            from={getNodeCenter(conn.from)}
            to={getNodeCenter(conn.to)}
            isSelected={state.selectedConnectionId === conn.id}
            onClick={() => {}}
          />
        ))}
      </svg>

      {/* Nodes layer */}
      <div
        style={{
          transform: `translate(${state.offsetX}px, ${state.offsetY}px) scale(${state.scale})`,
          transformOrigin: '0 0',
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
        }}
      >
        {state.nodes.map(node => (
          <BaseNode
            key={node.id}
            id={node.id}
            type={node.type}
            x={node.x}
            y={node.y}
            label={node.label}
            isSelected={state.selectedNodeId === node.id}
            isConnecting={state.connectingFrom === node.id}
            onSelect={handleNodeSelect}
            onMove={handleNodeMove}
            onOutputClick={handleOutputClick}
            onInputClick={handleInputClick}
          />
        ))}
      </div>

      {/* Connecting indicator */}
      {state.connectingFrom && (
        <div
