            transform: 'translateX(-50%)',
            backgroundColor: '#3b82f6',
            color: 'white',
            padding: '8px 16px',
            borderRadius: '9999px',
            fontSize: '14px',
            fontWeight: 500,
            zIndex: 100,
          }}
        >
          Click on a node to connect
        </div>
      )}
    </div>
  );
}
