/**
 * BaseNode — Draggable node component for Forge canvas
 * Base component for all node types with drag handling
 */

import React, { useCallback, useState } from 'react';

export interface BaseNodeProps {
  id: string;
  type: 'agent' | 'trigger';
  x: number;
  y: number;
  label: string;
  isSelected: boolean;
  isConnecting: boolean;
  onSelect: (id: string | null) => void;
  onMove: (id: string, x: number, y: number) => void;
  onOutputClick: (nodeId: string) => void;
  onInputClick: (nodeId: string) => void;
}

export function BaseNode({
  id,
  type,
  x,
  y,
  label,
  isSelected,
  isConnecting,
  onSelect,
  onMove,
  onOutputClick,
  onInputClick,
}: BaseNodeProps): JSX.Element {
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(id);
    setIsDragging(true);
    setDragOffset({
      x: e.clientX - x,
      y: e.clientY - y,
    });
  }, [id, x, y, onSelect]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!isDragging) return;
    e.stopPropagation();
    const newX = e.clientX - dragOffset.x;
    const newY = e.clientY - dragOffset.y;
    onMove(id, newX, newY);
  }, [isDragging, dragOffset, id, onMove]);

  const handleMouseUp = useCallback(() => {
    setIsDragging(false);
  }, []);

  const handleOutputClick = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    onOutputClick(id);
  }, [id, onOutputClick]);

  const handleInputClick = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    onInputClick(id);
  }, [id, onInputClick]);

  const getBorderColor = (): string => {
    if (isSelected) return '#3b82f6';
    if (isConnecting) return '#93c5fd';
    return '#e2e8f0';
  };

  const getIcon = (): string => {
    switch (type) {
      case 'trigger':
        return '⚡';
      case 'agent':
        return '🤖';
      default:
        return '📦';
    }
  };

  return (
    <div
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      style={{
        position: 'absolute',
        left: x,
        top: y,
        width: 200,
        backgroundColor: '#ffffff',
        border: `2px solid ${getBorderColor()}`,
        borderRadius: 8,
        boxShadow: isSelected
          ? '0 4px 12px rgba(59, 130, 246, 0.3)'
          : '0 2px 8px rgba(0, 0, 0, 0.1)',
        cursor: isDragging ? 'grabbing' : 'grab',
        userSelect: 'none',
        zIndex: isSelected ? 10 : 1,
      }}
    >
      {/* Header */}
      <div
        style={{
          padding: '12px',
          borderBottom: '1px solid #f1f5f9',
          display: 'flex',
          alignItems: 'center',
          gap: 8,
        }}
      >
        <span style={{ fontSize: 16 }}>{getIcon()}</span>
        <span
          style={{
            fontWeight: 600,
            fontSize: 14,
            color: '#1e293b',
          }}
        >
          {label}
        </span>
      </div>

      {/* Body */}
      <div
        style={{
          padding: 12,
          fontSize: 12,
          color: '#64748b',
        }}
      >
        {type === 'trigger' ? 'Workflow trigger' : 'AI agent step'}
      </div>

      {/* Input port */}
      <div
        onClick={handleInputClick}
        style={{
          position: 'absolute',
          left: -8,
          top: '50%',
          transform: 'translateY(-50%)',
          width: 16,
          height: 16,
          borderRadius: '50%',
          backgroundColor: isConnecting ? '#3b82f6' : '#e2e8f0',
          border: '2px solid #ffffff',
          cursor: 'pointer',
        }}
      />

      {/* Output port */}
      <div
        onClick={handleOutputClick}
        style={{
          position: 'absolute',
          right: -8,
          top: '50%',
          transform: 'translateY(-50%)',
          width: 16,
          height: 16,
          borderRadius: '50%',
          backgroundColor: '#3b82f6',
          border: '2px solid #ffffff',
          cursor: 'pointer',
        }}
      />
    </div>
  );
}

export default BaseNode;
